import Testmonial from "../components/Testimonial";

function Blog() {

    const blogList = [
        {
            id: 1,
            title: "Strong Modeling Portfolio",
            imageSrc: "friends-working-discussion-meeting-sharing-ideas-concept.jpg",
            content: "A professional portfolio is one of the most important tools for any model entering the fashion industry."
        },
        {
            id: 2,
            title: "Runway Confidence",
            imageSrc: "silhouette-woman-with-laptop-side-view-shadow-back-lit-young.jpg",
            content: "Walking the runway is one of the most exciting experiences in the modeling world."
        },
        {
            id: 3,
            title: "Brand Campaign Models",
            imageSrc: "women-using-laptops-sofa-together.jpg",
            content: "Models play a vital role in helping brands communicate their identity and message through visual storytelling."
        }
    ];
    return (
        <>
            <section >
                <div className="container">
                    <div className="row">
                        <div className="col-md-8">
                            <div className="cls-home-cont-imgs1 mb-4 cls-blog-main-img" ></div>
                            <div className="cls-blog-main">
                                <h5>The Journey of a Modern Model</h5>
                                <p>The world of modeling has evolved far beyond traditional runway shows and photoshoots. Today, models represent brands, influence audiences, and play a key role in shaping fashion trends. With the rise of digital platforms, models now have more opportunities to build their presence and connect with a global audience.</p>

                                <p>Success in the modeling industry requires more than just appearance. Confidence, professionalism, and dedication are essential qualities that help models stand out. From preparing for photoshoots to attending castings and working with creative teams, every step plays an important role in building a strong career. As the fashion industry continues to grow and change, new opportunities are constantly emerging. Models today can work across fashion campaigns, digital media, advertisements, and brand promotions, making the journey both exciting and full of possibilities.</p>
                                <div className="p-5 my-4 cls-blog-main-cogset" >
                                    <p>True confidence in modeling comes from embracing individuality and expressing it with authenticity.</p>
                                </div>
                                <p>A strong portfolio is also a crucial part of a model’s journey. It showcases versatility, style, and the ability to adapt to different creative concepts. Professional photoshoots and collaborations with photographers and designers help models present their best work to agencies and brands.</p>
                            </div>
                        </div>
                        <div className="col-md-4">
                            <div className="mb-5">
                                <h6>Recent Blog</h6>
                                {
                                    blogList.map((item) => (
                                        <div key={item.id} className="mb-3 cls-bloglist" >
                                            <div className="me-3 cls-bloglist-img" style={{
                                                backgroundImage: `url('/images/${item.imageSrc}')`, backgroundSize: "cover", backgroundPosition: "center"
                                            }}>
                                            </div>
                                            <div>
                                                <span><strong>{item.title}</strong></span>
                                                <p>{item.content}</p>
                                            </div>

                                        </div>
                                    ))
                                }
                            </div>

                            <div className="mt-4 mb-5">
                                <h6 className="d-flex">Tags</h6>
                                {
                                    [
                                        "Fashion",
                                        "Modeling",
                                        "Fashion Industry",
                                        "Runway",
                                        "Photoshoot",
                                        "Portfolio",
                                        "Brand Campaign",
                                        "Model Life",
                                        "Style",
                                        "Fashion Trends"
                                    ].map((item) => (
                                        <div key={item} className="btn me-3 align-items-center my-2 cls-tags" >
                                            <p className="p-0 m-0">{item}</p>
                                        </div>
                                    ))
                                }
                            </div>

                            <div className="cls-home-cont-imgs2 cls-explore-more" >
                                <div className="d-flex justify-content-center align-items-center h-100 cls-explore-more-content">
                                    <div className="text-center p-5">
                                        <h6>Creative Concepts</h6>
                                        <p>We develop unique fashion concepts that bring together models, styling, and creative direction.</p>
                                        <button className='btn commn-btn mt-3'>Explore More</button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div >
            </section >
            <section>
                <Testmonial />
            </section>
        </>
    )
}

export default Blog;